#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    // sample previous uFrame
    ret = texture( sampler_main, vUv ).xyz;

    // take the difference between the crisp and blurred images,
    // then add it back into the image.  Creates spots and stripes over uTime.
    ret += (ret - GetBlur2(vUv))*0.6;
    ret *= 0.9;

   // add noise:
   vec2 dither_uv = vUvOriginal*uTexSize.xy*texsize_noise_lq.zw * 0.4 + rand_frame.xy;
   ret += (texture(sampler_noise_lq, dither_uv).xyz-0.5)/256.0 * 12 * clamp01(audioHighSmooth-1);

   // desaturate over uTime, to keep the globs white
   ret = mix(ret, lum(ret), 0.04);

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    float rad_hq = length(vUv-0.5);
    vec2 d = uTexSize.zw*1;
    float f = 0.8;
    vec3 N;
    vec2 uv2 = vUvOriginal;
    N.x = ( GetPixel(uv2 + vec2(1,0)*d) - GetPixel(uv2-vec2(1,0)*d) ).x*f;
    N.y = ( GetPixel(uv2 + vec2(0,1)*d) - GetPixel(uv2-vec2(0,1)*d) ).x*f;
    N.x += ( GetBlur1(uv2 + vec2(1,0)*d) - GetBlur1(uv2-vec2(1,0)*d) ).x*(1-f);
    N.y += ( GetBlur1(uv2 + vec2(0,1)*d) - GetBlur1(uv2-vec2(0,1)*d) ).x*(1-f);
    N.z = -0.077;
    N = normalize(N);

    ret = N;

    vec3 light_pos = vec3(q9,q10,-0.8);


    vec3 P = vec3(vUvOriginal.xy*2-1, 0);
    vec3 L = normalize(light_pos - P);
    vec3 E = vec3(0,0,1);
    vec3 V = normalize(P-E);
    vec3 R = normalize( V + 2*N*dot(V,N) );

    // diffuse lighting:
    ret = clamp01(dot(N,L));
    ret *= vec3(1.2,0.9,0.7);
    ret *= normalize( GetBlur3(vUvOriginal).yzx );
    //ret = 0;

    // spec lighting:
    ret += pow(clamp01(dot(R,L)),32)*0.5;

    //ret *= 0.7;

  fragColor = ret;
}
